figure.sourcecode:
air-receipt = #6.18([ protected: bstr .cbor air-protected-header, unprotected: air-unprotected-header, payload: bstr .cbor air-claims, signature: bstr .size 64 ])
air-protected-header = { 1 => -8, ; alg: EdDSA (Ed25519) 3 => 61, ; content type: application/cwt }
air-unprotected-header = {}
air-claims = { ; --- Standard CWT/EAT claims --- 1 => tstr, ; iss: issuer 6 => uint, ; iat: issued-at (Unix seconds) 7 => bstr .size 16, ; cti: CWT ID (UUID v4, 16 bytes) 265 => "https://spec.cyntrisec.com/air/v1", ; eat_profile ? 10 => bstr, ; eat_nonce (optional)
; --- AIR private claims --- -65537 => tstr, ; model_id -65538 => tstr, ; model_version -65539 => sha256-hash, ; model_hash -65540 => sha256-hash, ; request_hash -65541 => sha256-hash, ; response_hash -65542 => sha256-hash, ; attestation_doc_hash -65543 => enclave-measurements, ; enclave_measurements -65544 => tstr, ; policy_version -65545 => uint, ; sequence_number -65546 => uint, ; execution_time_ms -65547 => uint, ; memory_peak_mb -65548 => tstr, ; security_mode ? -65549 => tstr, ; model_hash_scheme (optional) }
sha256-hash = bstr .size 32 sha384-hash = bstr .size 48
enclave-measurements = nitro-measurements / tdx-measurements
nitro-measurements = { "pcr0" => sha384-hash, ; image "pcr1" => sha384-hash, ; kernel + ramdisk "pcr2" => sha384-hash, ; application ? "pcr3" => sha384-hash, ; IAM role (optional) ? "pcr4" => sha384-hash, ; instance identity (optional) ? "pcr8" => sha384-hash, ; signing cert (optional) "measurement_type" => "nitro-pcr", }
tdx-measurements = { "pcr0" => sha384-hash, ; MRTD "pcr1" => sha384-hash, ; RTMR0 "pcr2" => sha384-hash, ; RTMR1 ? "pcr3" => sha384-hash, ; RTMR2 (optional) ? "pcr4" => sha384-hash, ; RTMR3 (optional) "measurement_type" => "tdx-mrtd-rtmr", }

; Attested Inference Receipt (AIR) v1 -- CDDL Schema ; Status: v1.0 FROZEN ; References: RFC 9052, RFC 8392, RFC 9711, RFC 8949, RFC 8610
air-receipt = #6.18([ protected: bstr .cbor air-protected-header, unprotected: air-unprotected-header, payload: bstr .cbor air-claims, signature: bstr .size 64 ])
air-protected-header = { 1 => -8, ; alg: EdDSA (Ed25519) 3 => 61, ; content type: application/cwt }
air-unprotected-header = {}
air-claims = { ; --- Standard CWT/EAT claims --- 1 => tstr, ; iss: issuer 6 => uint, ; iat: issued-at (Unix seconds) 7 => bstr .size 16, ; cti: CWT ID (UUID v4, 16 bytes) 265 => "https://spec.cyntrisec.com/air/v1", ; eat_profile ? 10 => bstr, ; eat_nonce (optional)
; --- AIR private claims --- -65537 => tstr, ; model_id -65538 => tstr, ; model_version -65539 => sha256-hash, ; model_hash -65540 => sha256-hash, ; request_hash -65541 => sha256-hash, ; response_hash -65542 => sha256-hash, ; attestation_doc_hash -65543 => enclave-measurements, ; enclave_measurements -65544 => tstr, ; policy_version -65545 => uint, ; sequence_number -65546 => uint, ; execution_time_ms -65547 => uint, ; memory_peak_mb -65548 => tstr, ; security_mode
; --- Optional claims (v1.0) --- ? -65549 => tstr, ; model_hash_scheme }
sha256-hash = bstr .size 32 sha384-hash = bstr .size 48
enclave-measurements = nitro-measurements / tdx-measurements
nitro-measurements = { "pcr0" => sha384-hash, ; image "pcr1" => sha384-hash, ; kernel + ramdisk "pcr2" => sha384-hash, ; application ? "pcr3" => sha384-hash, ; IAM role (optional) ? "pcr4" => sha384-hash, ; instance identity (optional) ? "pcr8" => sha384-hash, ; signing cert (optional) "measurement_type" => "nitro-pcr", }
tdx-measurements = { "pcr0" => sha384-hash, ; MRTD "pcr1" => sha384-hash, ; RTMR0 "pcr2" => sha384-hash, ; RTMR1 ? "pcr3" => sha384-hash, ; RTMR2 (optional) ? "pcr4" => sha384-hash, ; RTMR3 (optional) "measurement_type" => "tdx-mrtd-rtmr", }
